/* TimeWalk Japan module: Free Views of Tokyo */
if (!defined('ABSPATH')) exit;
final class TWJ_Free_Views_Module {
 const VERSION='1.0.0';
 function __construct(){add_action('wp_loaded',array($this,'publish_page'),40);add_shortcode('timewalk_free_views',array($this,'shortcode'));add_filter('the_content',array($this,'append_links'),30);add_action('wp_enqueue_scripts',array($this,'assets'));add_action('wp_footer',array($this,'footer_link'),30);add_filter('document_title_parts',array($this,'title'),20);add_action('wp_head',array($this,'meta'),2);}
 private function url($slug){$p=get_page_by_path($slug,OBJECT,'page');return $p?get_permalink($p):home_url('/'.$slug.'/');}
 function publish_page(){$p=get_page_by_path('free-views-tokyo',OBJECT,'page');$content='<!-- wp:shortcode -->[timewalk_free_views]<!-- /wp:shortcode -->';$a=array('post_type'=>'page','post_status'=>'publish','post_title'=>'Free Views of Tokyo','post_name'=>'free-views-tokyo','post_content'=>$content,'comment_status'=>'closed','ping_status'=>'closed');if($p)$a['ID']=$p->ID;$id=$p?wp_update_post(wp_slash($a),true):wp_insert_post(wp_slash($a),true);if(!is_wp_error($id)&&$id){update_post_meta($id,'_twj_free_views','1');update_post_meta($id,'_twj_seo_title','Free Views of Tokyo | Observation Decks, Rooftops and Historic Cityscapes');update_post_meta($id,'_twj_meta_description','Discover free observation decks, rooftop gardens and hidden viewpoints across Tokyo. Learn what you can see, how to visit, and the history behind each cityscape.');update_post_meta($id,'_yoast_wpseo_title','Free Views of Tokyo | Observation Decks, Rooftops and Historic Cityscapes');update_post_meta($id,'_yoast_wpseo_metadesc','Discover free observation decks, rooftop gardens and hidden viewpoints across Tokyo. Learn what you can see, how to visit, and the history behind each cityscape.');}}
 private function spots(){return array(
 array('Tokyo Metropolitan Government Building Observatories','Shinjuku','Public observation rooms','Indoor','Day, sunset and night','A 202-metre view across central Tokyo, Mount Fuji on clear days and the changing skyline of west Shinjuku.','Government architecture, postwar metropolitan growth and the development of Shinjuku as a high-rise centre.','Tochomae / Shinjuku','Free admission; no reservation. Check current closures before visiting.','https://www.zaimu.metro.tokyo.lg.jp/tochousha/goannai/tenbou'),
 array('Hokutopia 17F Observation Lobby','Kita','Public observation lobby','Indoor','Day, sunset and railway views','A broad view over Oji, the Arakawa lowlands and trains approaching the city.','Railway corridors, river terraces and the geography of northern Tokyo.','Oji','Free admission. Details being prepared.',''),
 array('KITTE Garden','Marunouchi','Rooftop garden','Outdoor','Day, sunset and railway views','A close view of Tokyo Station, Marunouchi and trains entering the city centre.','Tokyo Station architecture, railway history and the rebuilding of Marunouchi.','Tokyo / Nijubashimae','Free entry; weather and maintenance closures may apply.',''),
 array('Marunouchi House 7F Terrace','Marunouchi','Commercial terrace','Outdoor','Sunset, night and architecture','A terrace looking toward Tokyo Station and the towers of Marunouchi.','Commercial redevelopment and the relationship between the historic station and the modern business district.','Tokyo / Otemachi','Terrace access is generally free; seating and restaurant areas may have conditions.',''),
 array('Nerima City Office 20F Observation Lobby','Nerima','Public observation lobby','Indoor','Day, sunset and night','A western Tokyo panorama with residential districts, railways and distant mountains.','How suburban Tokyo expanded around private railway lines and ward centres.','Nerima','Free admission. Check current opening days before visiting.',''),
 array('Sky Carrot Observation Lobby','Sangenjaya','Public observation lobby','Indoor','Sunset and night','A high view over Setagaya, central Tokyo and the western horizon.','The growth of Sangenjaya as a transport junction and the changing skyline beyond it.','Sangenjaya','Free admission. Check the official facility schedule.',''),
 array('Toshima City Office Rooftop Garden “Toshima no Mori”','Ikebukuro','Rooftop garden','Outdoor','Day and urban history','A planted rooftop above the ward office, with views into the dense city around Ikebukuro.','Civic architecture, ecological design and the redevelopment of the former ward-office site.','Higashi-Ikebukuro','Free entry; seasonal hours and weather closures apply.',''),
 array('Tower Hall Funabori Observation Room','Edogawa','Public observation room','Indoor','Day, sunset and night','A 103-metre view across eastern Tokyo, the lowlands and the river landscape.','Floodplain geography, eastern suburban growth and the city’s relationship with its rivers.','Funabori','Free admission. Check current facility hours before visiting.','')
 );}
 function cards(){ $html='';foreach($this->spots() as $s){$html.='<article class="twj-view-card"><div class="twj-view-card__body"><p class="twj-view-area">'.esc_html($s[1]).'</p><h3>'.esc_html($s[0]).'</h3><div class="twj-view-tags"><span>'.esc_html($s[2]).'</span><span>'.esc_html($s[3]).'</span><span>Best for: '.esc_html($s[4]).'</span></div><p>'.esc_html($s[5]).'</p><dl><dt>What to notice</dt><dd>'.esc_html($s[6]).'</dd><dt>Nearest station</dt><dd>'.esc_html($s[7]).'</dd><dt>Free-entry condition</dt><dd>'.esc_html($s[8]).'</dd></dl>'.($s[9]?'<a class="twj-view-official" href="'.esc_url($s[9]).'" target="_blank" rel="noopener">Check official information</a>':'<p class="twj-view-status">Guide coming soon</p>').'</div></article>';}return $html;}
 function shortcode(){return '<div class="twj-free-views"><section class="twj-free-hero"><h1>Free Views of Tokyo</h1><p>Tokyo’s skyline is not limited to expensive towers. City halls, public observation rooms, rooftop gardens and commercial terraces offer remarkable views for free. These places also reveal how Tokyo grew—from Edo-period coastlines and railway corridors to modern redevelopment districts.</p><p><a class="twj-btn" href="#viewpoints">Browse the Viewpoints</a> <a class="twj-btn twj-btn-secondary" href="'.esc_url($this->url('tokyo')).'">Explore Tokyo</a></p></section><section><h2>More Than a Skyline</h2><p>This guide focuses on viewpoints that can be entered without an observation-deck ticket. It includes government buildings, public facilities, rooftop gardens and shared commercial terraces. The aim is not only to find a beautiful view, but to read Tokyo’s history, geography, transport, architecture and redevelopment from above. Hours, closures and access conditions can change, so always confirm current official information before visiting.</p></section><section id="viewpoints"><h2>Free Viewpoints in Tokyo</h2><div class="twj-view-grid">'.$this->cards().'</div></section><section><h2>Choose a View</h2><div class="twj-view-choices"><a href="#viewpoints">Tokyo Station and Marunouchi</a><a href="#viewpoints">Railway Views</a><a href="#viewpoints">Sunset</a><a href="#viewpoints">Night Views</a><a href="#viewpoints">Architecture</a><a href="#viewpoints">Urban History</a><a href="#viewpoints">Indoor Views for Rainy Days</a><a href="#viewpoints">Rooftop Gardens and Terraces</a></div></section><section><h2>Before You Visit</h2><ul><li>Opening hours, closure days and entry procedures may change.</li><li>Respect shops, restaurant guests and other visitors in shared commercial spaces.</li><li>Tripods, long photo sessions and commercial photography may be restricted.</li><li>Weather, glass, direction and seasonal light can change what is visible.</li><li>Check each facility’s official website before travelling.</li></ul></section><section><h2>Read Tokyo from Above</h2><p>From above, Tokyo becomes easier to read. Railway lines reveal how neighborhoods developed. Rivers and lowlands explain the city’s geography. Former industrial sites show the scale of redevelopment. Preserved buildings reveal how older Tokyo survives inside the modern city.</p></section><section><h2>Keep Exploring Tokyo</h2><div class="twj-related-links"><a href="'.esc_url($this->url('tokyo')).'">Explore Tokyo</a><a href="'.esc_url($this->url('self-guided-walks')).'">Self-Guided Walks</a><a href="'.esc_url($this->url('stories')).'">Stories</a><a href="'.esc_url($this->url('events')).'">Events</a></div></section><section><h2>Frequently Asked Questions</h2><details><summary>Are these observation decks really free?</summary><p>The listed viewpoints do not normally require a paid observation-deck ticket, but some commercial terraces may have rules for seating or restaurant areas.</p></details><details><summary>Do I need a reservation?</summary><p>Most do not require reservations, but rules differ by facility and can change.</p></details><details><summary>Can I visit at night?</summary><p>Some viewpoints stay open into the evening, while rooftop gardens and government facilities may close earlier.</p></details><details><summary>Are the viewpoints open every day?</summary><p>No. Regular closure days, maintenance, weather and special events can affect access.</p></details><details><summary>Can I use a tripod?</summary><p>Restrictions differ. Many public observation spaces limit tripods or long photo sessions.</p></details><details><summary>Which free viewpoint is best for a first-time visitor to Tokyo?</summary><p>The Tokyo Metropolitan Government Building is a practical introduction because it offers a high panoramic view and clear orientation across the city.</p></details><details><summary>Are there indoor viewpoints for rainy days?</summary><p>Yes. Government-building observation rooms and indoor lobbies are useful options, although visibility may be reduced.</p></details></section><section class="twj-free-cta"><h2>See Tokyo Differently</h2><p>A good view is more than a photograph. It can show how Tokyo’s railways, waterways, neighborhoods and buildings fit together. Choose a viewpoint, look closely, and discover the history below.</p><p><a class="twj-btn" href="'.esc_url($this->url('tokyo')).'">Explore Tokyo</a> <a class="twj-btn twj-btn-secondary" href="'.esc_url($this->url('stories')).'">Read Stories</a></p></section></div>';}
 function append_links($content){if(!in_the_loop()||!is_main_query())return$content;if(is_page('free-views-tokyo'))return$content;$box='<section class="twj-free-link-card"><h2>Free Views of Tokyo</h2><p>See Tokyo from free observation decks, rooftop gardens and lesser-known viewpoints—and discover the history, architecture and urban change behind the view.</p><a class="twj-btn" href="'.esc_url($this->url('free-views-tokyo')).'">Explore Free Views</a></section>';if(is_front_page()||is_page(15))return$content.$box;if(is_page('tokyo'))return$content.$box;return$content;}
 function footer_link(){?><script>document.addEventListener('DOMContentLoaded',function(){if(document.querySelector('a[href*="free-views-tokyo"]'))return;var groups=document.querySelectorAll('footer nav,footer .wp-block-navigation,footer .footer-widget-area');if(groups.length){var a=document.createElement('a');a.href='<?php echo esc_js($this->url('free-views-tokyo'));?>';a.textContent='Free Views of Tokyo';groups[0].appendChild(a);}});</script><?php }
 function title($parts){if(is_page('free-views-tokyo'))$parts['title']='Free Views of Tokyo | Observation Decks, Rooftops and Historic Cityscapes';return$parts;}
 function meta(){if(is_page('free-views-tokyo'))echo '<meta name="description" content="Discover free observation decks, rooftop gardens and hidden viewpoints across Tokyo. Learn what you can see, how to visit, and the history behind each cityscape.">';}
 function assets(){wp_register_style('twj-free-views',false,array(),self::VERSION);wp_enqueue_style('twj-free-views');wp_add_inline_style('twj-free-views','.twj-free-views section{margin:0 0 56px}.twj-free-hero{padding:34px 0 8px}.twj-free-hero h1{font-size:clamp(2.2rem,6vw,4.5rem);line-height:1.02}.twj-btn{display:inline-block;padding:10px 16px;border-radius:999px;background:#172033;color:#fff!important;text-decoration:none!important;font-weight:700}.twj-btn-secondary{background:#fff;color:#172033!important;border:1px solid #172033}.twj-view-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}.twj-view-card{border:1px solid #e2e7ed;border-radius:12px;background:#fff;box-shadow:0 6px 18px rgba(23,32,51,.06)}.twj-view-card__body{padding:18px}.twj-view-area{margin:0 0 5px!important;font-size:.75rem;font-weight:700;text-transform:uppercase;color:#607080}.twj-view-card h3{margin:0 0 10px!important;font-size:1.12rem}.twj-view-tags{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:12px}.twj-view-tags span{font-size:.7rem;padding:4px 7px;background:#eef3f6;border-radius:999px}.twj-view-card dl{margin:14px 0}.twj-view-card dt{font-weight:700;font-size:.78rem}.twj-view-card dd{margin:0 0 8px;font-size:.86rem}.twj-view-status{font-weight:700;color:#697386}.twj-view-choices,.twj-related-links{display:flex;flex-wrap:wrap;gap:10px}.twj-view-choices a,.twj-related-links a{padding:8px 11px;border:1px solid #d5dce5;border-radius:8px;text-decoration:none!important}.twj-free-link-card{margin:54px 0!important;padding:24px;border:1px solid #e2e7ed;border-radius:12px;background:#f7f9fb}.twj-free-link-card h2{margin-top:0!important}.twj-free-views details{border-top:1px solid #e2e7ed;padding:12px 0}.twj-free-views summary{font-weight:700;cursor:pointer}@media(max-width:900px){.twj-view-grid{grid-template-columns:repeat(2,minmax(0,1fr))}}@media(max-width:600px){.twj-view-grid{grid-template-columns:1fr}.twj-free-hero p .twj-btn{margin:0 5px 8px 0}}');}
}
new TWJ_Free_Views_Module();
